#include<bits/stdc++.h>
using namespace std;
struct node
{
    int t,f,h;
    bool operator<(const node&b)const
    {
        return t<b.t;
    }
}a[110];
int f[110];
int main()
{
    int n,h;
    scanf("%d%d",&h,&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d%d%d",&a[i].t,&a[i].f,&a[i].h);
    }
    sort(a+1,a+1+n);
    f[0]=10;
    for(int i=1;i<=n;i++)
    {
        for(int j=h;j>=0;j--)
        {
            if(f[j]<a[i].t)
            {
                continue;
            }
            if(j+a[i].h>=h)
            {
                printf("%d",a[i].t);
                return 0;
            }
            f[j+a[i].h]=max(f[j+a[i].h],f[j]);
            f[j]+=a[i].f;
        }
    }
    printf("%d",f[0]);
    return 0;
}
